  ('tennis-nwt-summer-camp-ages-8-12', 'Tennis NWT Summer Camp (Ages 8-12)', 'Tennis NWT Summer Camps are designed for beginner and intermediate youth players ages 8''12. Led by Tennis Canada''certified coaches, these camps introduce young players to the fundamentals of tennis in a fun, supportive, and positive environment. Camp activities focus on skill development, confidence building, and a love for the game - all while keeping things light and enjoyable. Time: 09:00 am - 12:00 pm.', 'Tennis NWT / City of Yellowknife', 'Sports', 8, 12, 'Yellowknife', 'Parks, 4807 - 52 St', NULL, '2026-06-22', '2026-06-26', NULL, 'paid', 162.38, 'https://yellowknife.perfectmind.com/Contacts/BookMe4BookingPages/BookingCoursesPage?calendarId=be3ea5f4-ef36-101d-d685-729ff55fe6b0&widgetId=15f6af07-39c5-473e-b053-96653f77a406&embed=False', NULL, NULL, 'https://yellowknife.perfectmind.com/Contacts/BookMe4BookingPages/BookingCoursesPage?calendarId=be3ea5f4-ef36-101d-d685-729ff55fe6b0&widgetId=15f6af07-39c5-473e-b053-96653f77a406&embed=False', NULL, 'active', false),
