  ('tennis-nwt-summer-camp-ages-8-12-6', 'Tennis NWT Summer Camp (Ages 8-12)', 'Tennis NWT Summer Camps are designed for beginner and intermediate youth players ages 8''12. Led by Tennis Canada''certified coaches, these camps introduce young players to the fundamentals of tennis in a fun, supportive, and positive environment. Camp activities focus on skill development, confidence building, and a love for the game - all while keeping things light and enjoyable. Time: 09:00 am - 12:00 pm.', 'Tennis NWT / City of Yellowknife', 'Sports', 8, 12, 'Yellowknife', 'Parks, 4807 - 52 St', NULL, '2026-08-03', '2026-08-07', NULL, 'paid', 162.4, 'https://yellowknife.perfectmind.com/Contacts/BookMe4BookingPages/BookingCoursesPage?calendarId=be3ea5f4-ef36-101d-d685-729ff55fe6b0&widgetId=15f6af07-39c5-473e-b053-96653f77a406&embed=False', NULL, NULL, 'https://yellowknife.perfectmind.com/Contacts/BookMe4BookingPages/BookingCoursesPage?calendarId=be3ea5f4-ef36-101d-d685-729ff55fe6b0&widgetId=15f6af07-39c5-473e-b053-96653f77a406&embed=False', NULL, 'active', false),
  ('city-summer-camp-ages-5-6-week-seven', 'City Summer Camp (Ages 5-6)- Week Seven', 'Camp is a fun way for children to spend their Summer break. It is also a place to make a positive impact in children''s lives through the help of our camp leaders. The City of Yellowknife Summer Camp activities provide children with the skills in participation, forming friendships and socialization abilities. With successful implementation of camp leaders, campers will gain self-esteem and self-confidence through experiences and adventures at camp. Camp will be held at a number of City facilities including the Aquatic Centre, Library, Multiplex, & Fieldhouse. A list of daily drop off, and pick up locations will be provided to registrants in the days before camp starts. Time: 08:00 am - 05:00 pm.', 'City of Yellowknife', 'Camps', 5, 6, 'Yellowknife', 'Yellowknife Multiplex, 45 Kam Lake Road', NULL, '2026-08-04', '2026-08-07', NULL, 'paid', 274.08, 'https://yellowknife.perfectmind.com/Contacts/BookMe4BookingPages/BookingCoursesPage?calendarId=be3ea5f4-ef36-101d-d685-729ff55fe6b0&widgetId=15f6af07-39c5-473e-b053-96653f77a406&embed=False', NULL, NULL, 'https://yellowknife.perfectmind.com/Contacts/BookMe4BookingPages/BookingCoursesPage?calendarId=be3ea5f4-ef36-101d-d685-729ff55fe6b0&widgetId=15f6af07-39c5-473e-b053-96653f77a406&embed=False', NULL, 'active', false),
